const extractData = $input.first().json.data || $input.first().json;
const triggerData = $('New Referral Letter').item.json;

const referral = extractData;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Referring physician info
const refMD = referral.referringPhysician || {};

// Format ICD codes
const icdCodes = referral.icdCodes || [];
const icdList = icdCodes.join(', ') || 'None specified';

// Format medications
const meds = referral.currentMedications || [];
const medsList = meds.join(', ') || 'None listed';

// Format allergies
const allergies = referral.allergies || [];
const allergiesList = allergies.join(', ') || 'NKDA';

// Determine department based on requested service
const service = (referral.requestedService || '').toLowerCase();
let department = 'General';

if (service.includes('cardio') || service.includes('heart')) department = 'Cardiology';
else if (service.includes('ortho') || service.includes('bone') || service.includes('joint')) department = 'Orthopedics';
else if (service.includes('neuro') || service.includes('brain')) department = 'Neurology';
else if (service.includes('gastro') || service.includes('gi')) department = 'Gastroenterology';
else if (service.includes('pulmo') || service.includes('lung')) department = 'Pulmonology';
else if (service.includes('oncol') || service.includes('cancer')) department = 'Oncology';
else if (service.includes('derma') || service.includes('skin')) department = 'Dermatology';
else if (service.includes('endo') || service.includes('diabetes')) department = 'Endocrinology';
else if (service.includes('psych') || service.includes('mental')) department = 'Psychiatry';
else if (service.includes('surgery')) department = 'Surgery';
else if (service.includes('radiol') || service.includes('imaging')) department = 'Radiology';

// Determine priority flag
const urgency = (referral.urgencyLevel || 'routine').toLowerCase();
let priorityFlag = '🟢';
if (urgency.includes('stat') || urgency.includes('emergent')) priorityFlag = '🔴';
else if (urgency.includes('urgent')) priorityFlag = '🟡';

return [{
  json: {
    patientName: referral.patientName || 'Unknown',
    dateOfBirth: referral.dateOfBirth || 'N/A',
    gender: referral.gender || 'N/A',
    phone: referral.phone || 'N/A',
    insuranceProvider: referral.insuranceProvider || 'Unknown',
    insuranceId: referral.insuranceId || 'N/A',
    referringMDName: refMD.name || 'Unknown',
    referringMDPractice: refMD.practice || 'N/A',
    referringMDPhone: refMD.phone || 'N/A',
    referringMDFax: refMD.fax || 'N/A',
    referralDate: referral.referralDate || 'N/A',
    diagnosis: referral.diagnosis || 'Not specified',
    icdCodes: icdList,
    urgencyLevel: referral.urgencyLevel || 'Routine',
    priorityFlag: priorityFlag,
    requestedService: referral.requestedService || 'Not specified',
    requestedProvider: referral.requestedProvider || 'Any available',
    department: department,
    currentMedications: medsList,
    allergies: allergiesList,
    specialInstructions: referral.specialInstructions || 'None',
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

